// stores/websocket.ts 改进
import { defineStore } from 'pinia'

export const useWebSocketStore = defineStore('websocket', () => {
  const ws = ref<WebSocket | null>(null)
  const connected = ref(false)
  const reconnectAttempts = ref(0)
  const maxRetries = 5

  const eventHandlers = new Map<string, Set<Function>>()

  function connect(url: string) {
    ws.value = new WebSocket(url)

    ws.value.onopen = () => {
      connected.value = true
      reconnectAttempts.value = 0
      console.log('WebSocket connected')
    }

    ws.value.onclose = () => {
      connected.value = false
      // 自动重连
      if (reconnectAttempts.value < maxRetries) {
        setTimeout(() => {
          reconnectAttempts.value++
          connect(url)
        }, 3000 * reconnectAttempts.value)
      }
    }

    ws.value.onmessage = (event) => {
      const { event: type, data } = JSON.parse(event.data)
      const handlers = eventHandlers.get(type) || new Set()
      handlers.forEach(handler => handler(data))
    }
  }

  function on(event: string, handler: Function) {
    if (!eventHandlers.has(event)) {
      eventHandlers.set(event, new Set())
    }
    eventHandlers.get(event)!.add(handler)
  }

  function off(event: string, handler: Function) {
    eventHandlers.get(event)?.delete(handler)
  }

  return { ws, connected, connect, on, off }
})
```

