### 方案 2: 集成 AutoIterationEngine 与 Dashboard（P0）

**目标**: 让迭代数据实时推送到 Dashboard

```typescript
// auto-iteration.ts 改进
export class AutoIterationEngine {
  private iterationService?: IterationService
  private realtimeService?: RealtimeService

  constructor(config: Partial<IterationConfig> = {}) {
    this.config = { /* ... */ }

    // 获取 Dashboard 服务
    try {
      const services = getServices()
      this.iterationService = services?.iterationService
      this.realtimeService = services?.realtimeService
    } catch (error) {
      console.warn('Dashboard services not available, running standalone')
    }
  }

  private async notifyIterationStart(iteration: number, requirement: string) {
    if (!this.iterationService) return

    await this.iterationService.create({
      iterationNumber: iteration,
      status: 'running',
      requirement,
      startedAt: new Date()
    })

    this.realtimeService?.broadcast({
      event: 'iteration.started',
      data: { iteration, requirement }
    })
  }

  private async notifyAgentStart(agentName: string, task: string) {
    this.realtimeService?.broadcast({
      event: 'agent.status_changed',
      data: {
        agent: agentName,
        status: 'running',
        task
      }
    })
  }

  private async notifyProgress(phase: string, progress: number, message: string) {
    this.realtimeService?.broadcast({
      event: 'iteration.progress',
      data: {
        phase,
        progress,
        message,
        timestamp: new Date()
      }
    })
  }

  async start() {
    this.isRunning = true

    while (this.isRunning && this.shouldContinue()) {
      const iterationNum = this.iterationCount + 1

      // 通知迭代开始
      await this.notifyIterationStart(iterationNum, this.requirement)

      // Phase 1: 产品经理
      await this.notifyAgentStart('ProductManager', '分析需求')
      await this.notifyProgress('product_manager', 10, '开始分析需求...')

      const pmResult = await this.productManager.executeAndCollect(/* ... */)
      await this.notifyProgress('product_manager', 100, '需求分析完成')

      // Phase 2: 架构师
      await this.notifyAgentStart('Architect', '设计架构')
      await this.notifyProgress('architect', 30, '设计系统架构...')

      const archResult = await this.agents.architect.executeAndCollect(/* ... */)
      await this.notifyProgress('architect', 100, '架构设计完成')

      // ... 其他 Agent

      // 通知迭代完成
      await this.notifyIterationComplete(iterationNum)
    }
  }
}
